package queries

import (
	"context"
	"encoding/json"
	"log"
	"net/http"
	"strings"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/harusame0616/ijuku/apps/api/lib/response"
)

type listCategoriesQuery interface {
	ListCategories(ctx context.Context) ([]db.ListCategoriesRow, error)
}

type ListCategoriesHandler struct {
	q listCategoriesQuery
}

func NewListCategoriesHandler(q listCategoriesQuery) *ListCategoriesHandler {
	return &ListCategoriesHandler{q: q}
}

type categoryNode struct {
	Slug     string         `json:"slug"`
	Name     string         `json:"name"`
	Children []categoryNode `json:"children,omitempty"`
}

type listCategoriesResponse struct {
	Categories []categoryNode `json:"categories"`
}

func (h *ListCategoriesHandler) ListCategoriesHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	rows, err := h.q.ListCategories(r.Context())
	if err != nil {
		log.Printf("ListCategories error: %v", err)
		response.WriteInternalServerErrorResponse(w)
		return
	}

	tree := buildTree(rows)
	_ = json.NewEncoder(w).Encode(listCategoriesResponse{Categories: tree})
}

// buildTree は path 昇順でソートされた categories から階層構造を組み立てる
func buildTree(rows []db.ListCategoriesRow) []categoryNode {
	type entry struct {
		node     *categoryNode
		children *[]categoryNode
	}
	byPath := map[string]*entry{}
	roots := []categoryNode{}

	for _, row := range rows {
		segments := strings.Split(row.Path, ".")
		slug := segments[len(segments)-1]
		node := categoryNode{Slug: slug, Name: row.Name}

		if len(segments) == 1 {
			roots = append(roots, node)
			byPath[row.Path] = &entry{
				node:     &roots[len(roots)-1],
				children: &roots[len(roots)-1].Children,
			}
			continue
		}

		parentPath := strings.Join(segments[:len(segments)-1], ".")
		parent, ok := byPath[parentPath]
		if !ok {
			continue
		}
		*parent.children = append(*parent.children, node)
		appended := &(*parent.children)[len(*parent.children)-1]
		byPath[row.Path] = &entry{
			node:     appended,
			children: &appended.Children,
		}
	}

	return roots
}

package queries

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"net/http/httptest"
	"net/url"
	"testing"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/harusame0616/ijuku/apps/api/lib/env"
	"github.com/jackc/pgx/v5/pgxpool"
)

const (
	testCategoryID = "10000000-0000-0000-0000-000000000000"
	testAuthorID   = "20000000-0000-0000-0000-000000000000"
	titleCourseID  = "30000000-0000-0000-0000-000000000001"
	descCourseID   = "30000000-0000-0000-0000-000000000002"
)

func databaseURL() string {
	return env.Require("DATABASE_URL")
}

func setupTestData(ctx context.Context, pool *pgxpool.Pool) error {
	cleanupTestData(ctx, pool)

	_, err := pool.Exec(ctx,
		`INSERT INTO categories (category_id, name, path) VALUES ($1, 'テストカテゴリ', 'test')`,
		testCategoryID,
	)
	if err != nil {
		return fmt.Errorf("カテゴリの挿入に失敗しました: %w", err)
	}

	_, err = pool.Exec(ctx,
		`INSERT INTO authors (author_id, name, profile, slug) VALUES ($1, 'テスト著者', 'テストプロフィール', 'get-courses-author')`,
		testAuthorID,
	)
	if err != nil {
		return fmt.Errorf("著者の挿入に失敗しました: %w", err)
	}

	_, err = pool.Exec(ctx,
		`INSERT INTO courses (course_id, title, description, slug, tags, publish_status, category_id, author_id, visibility)
		 VALUES ($1, 'タイトル一致テスト専用コース', '一般説明', 'test-title-course', '[]', 'published', $2, $3, 'public')`,
		titleCourseID, testCategoryID, testAuthorID,
	)
	if err != nil {
		return fmt.Errorf("タイトル一致コースの挿入に失敗しました: %w", err)
	}

	_, err = pool.Exec(ctx,
		`INSERT INTO courses (course_id, title, description, slug, tags, publish_status, category_id, author_id, visibility)
		 VALUES ($1, '通常コースB', '説明文一致テスト専用テキスト', 'test-desc-course', '[]', 'published', $2, $3, 'public')`,
		descCourseID, testCategoryID, testAuthorID,
	)
	if err != nil {
		return fmt.Errorf("説明一致コースの挿入に失敗しました: %w", err)
	}

	for i := 1; i <= 201; i++ {
		courseID := fmt.Sprintf("40000000-0000-0000-0000-%012d", i)
		slug := fmt.Sprintf("test-page-%d", i)
		_, err = pool.Exec(ctx,
			`INSERT INTO courses (course_id, title, description, slug, tags, publish_status, category_id, author_id, visibility)
			 VALUES ($1, 'ページネーションテスト', 'ページコース説明', $2, '[]', 'published', $3, $4, 'public')`,
			courseID, slug, testCategoryID, testAuthorID,
		)
		if err != nil {
			return fmt.Errorf("ページネーションコース %d の挿入に失敗しました: %w", i, err)
		}
	}

	return nil
}

